export class SimpleCrypto{static async hash(e){if("undefined"!=typeof window&&window.crypto&&window.crypto.subtle){let t=(new TextEncoder).encode(e),r=await window.crypto.subtle.digest("SHA-256",t);return Array.from(new Uint8Array(r)).map((e=>e.toString(16).padStart(2,"0"))).join("")}{let t=require("crypto").createHash("sha256");return t.update(e),t.digest("hex")}}static async getHashedKey(e){let t=await this.hash(e);return(new TextEncoder).encode(t).slice(0,32)}static async encrypt(e,t){let r=await this.getHashedKey(t);if("undefined"!=typeof window&&window.crypto&&window.crypto.subtle){let t=await window.crypto.subtle.importKey("raw",r,{name:"AES-GCM",length:256},!1,["encrypt"]),n=window.crypto.getRandomValues(new Uint8Array(12)),a=(new TextEncoder).encode(e),i=await window.crypto.subtle.encrypt({name:"AES-GCM",iv:n,tagLength:128},t,a),c=new Uint8Array(n.length+i.byteLength);return c.set(n),c.set(new Uint8Array(i),n.length),c.reduce(((e,t)=>e+t.toString(16).padStart(2,"0")),"")}{const t=require("crypto");let n=t.randomBytes(12),a=t.createCipheriv("aes-256-gcm",r,n),i=Buffer.concat([a.update(e,"utf8"),a.final()]),c=a.getAuthTag();return Buffer.concat([n,i,c]).toString("hex")}}static async decrypt(e,t){try{let r=await this.getHashedKey(t);if("undefined"!=typeof window&&window.crypto&&window.crypto.subtle){let t=await window.crypto.subtle.importKey("raw",r,{name:"AES-GCM",length:256},!1,["decrypt"]),n=new Uint8Array(e.match(/.{1,2}/g).map((e=>parseInt(e,16)))),a=n.slice(0,12),i=n.slice(12),c=await window.crypto.subtle.decrypt({name:"AES-GCM",iv:a},t,i);return(new TextDecoder).decode(c)}{const t=require("crypto");let n=Buffer.from(e,"hex"),a=n.slice(0,12),i=n.slice(12,n.length-16),c=n.slice(n.length-16),o=t.createDecipheriv("aes-256-gcm",r,a);return o.setAuthTag(c),Buffer.concat([o.update(i),o.final()]).toString("utf8")}}catch(e){return null}}}